import numpy as np
import time

# Record when each customer is added
customer_add_times = {}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    # Record current time
    current_time = time.time()

    # Record the time stamp when a new customer is added
    for idx, customer in enumerate(unvisited_customers):
        if idx not in customer_add_times:
            customer_add_times[idx] = current_time

    if len(unvisited_customers) == 0:
        return None

    # Calculate distances from current truck position to each unvisited customer
    distances = [np.linalg.norm(cur_truck_pos - customer) for customer in unvisited_customers]

    # Evaluate potential route overlaps
    overlap_scores = [
        sum(np.exp(-np.linalg.norm(customer - other_truck)) for other_truck in all_truck_pos) 
        for customer in unvisited_customers
    ]

    # Time-based priority scoring
    time_scores = [
        current_time - customer_add_times[idx] 
        for idx in range(len(unvisited_customers))
    ]

    # Compute dynamic priority scores
    priority_scores = [
        0.5 * dist + 0.3 * overlap - 0.2 * time_score
        for dist, overlap, time_score in zip(distances, overlap_scores, time_scores)
    ]

    best_node = np.argmin(priority_scores)

    return best_node
